CONTAINER="concertacao-dev-wordpress"
# Procurar no site raiz páginas que contenham filtros como os da screenshot
# Os filtros são: Localidade, Estado, área de atuação, Tema Prioritário, 4 Amazônias
# Com query_id relacionado a artistas/mapa

docker exec -u www-data "$CONTAINER" wp eval '
$pages = get_posts([
    "post_type" => "page",
    "post_status" => "publish",
    "numberposts" => -1,
    "meta_key" => "_elementor_data",
]);
foreach ($pages as $page) {
    $data = get_post_meta($page->ID, "_elementor_data", true);
    if (strpos($data, "artista") !== false && strpos($data, "jet-smart-filter") !== false) {
        echo $page->ID . " - " . $page->post_title . "\n";
    }
}
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
docker exec -u www-data "$CONTAINER" wp --url="https://concertacao.local/cultura/" eval '
$data = get_post_meta(57548, "_elementor_data", true);
echo $data;
' 2>/dev/null > /tmp/atlas-cultura.json
echo "Tamanho: $(wc -c < /tmp/atlas-cultura.json)"

CONTAINER="concertacao-dev-wordpress"
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
$data = get_post_meta(57548, "_elementor_data", true);
echo $data;
' 2>/dev/null > /tmp/atlas-cultura.json
echo "Tamanho: $(wc -c < /tmp/atlas-cultura.json)"

CONTAINER="concertacao-dev-wordpress"
# Verificar quais são esses filtros JetSmartFilters por ID (são do subsite cultura)
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
$filter_ids = [51448, 51434, 40789, 83225, 79472, 40843];
foreach ($filter_ids as $id) {
    $post = get_post($id);
    if ($post) {
        echo $id . " - " . $post->post_title . " (" . $post->post_type . ")\n";
    } else {
        echo $id . " - NÃO ENCONTRADO\n";
    }
}
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
# Verificar os filtros disponíveis no subsite cultura relacionados a tema
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
$filters = get_posts([
    "post_type" => "jet-smart-filters",
    "post_status" => "publish",
    "numberposts" => -1,
]);
foreach ($filters as $f) {
    echo $f->ID . " - " . $f->post_title . "\n";
}
' 2>/dev/null | sort -t- -k1 -n

CONTAINER="concertacao-dev-wordpress"
# Verificar a configuração do filtro 51448 (Localidade)
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
$filter = get_post(51448);
$meta = get_post_meta(51448);
echo "Titulo: " . $filter->post_title . "\n";
echo "Meta keys: " . implode(", ", array_keys($meta)) . "\n";
// Mostrar o conteúdo principal do filtro
foreach ($meta as $key => $values) {
    if (strpos($key, "_") !== 0) {
        echo $key . ": " . print_r($values[0], true) . "\n";
    }
}
' 2>/dev/null | head -30

