CONTAINER="concertacao-dev-wordpress"
# Verificar o _filter_type, _data_source e _source_taxonomy do filtro 51448
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
$meta_keys = ["_filter_type", "_data_source", "_source_taxonomy", "_source_post_type", "_filter_label"];
foreach ($meta_keys as $key) {
    $val = get_post_meta(51448, $key, true);
    echo $key . ": " . print_r($val, true) . "\n";
}
echo "---\n";
foreach ($meta_keys as $key) {
    $val = get_post_meta(51434, $key, true);
    echo "51434 " . $key . ": " . print_r($val, true) . "\n";
}
echo "---\n";
foreach ($meta_keys as $key) {
    $val = get_post_meta(40789, $key, true);
    echo "40789 " . $key . ": " . print_r($val, true) . "\n";
}
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
# Verificar qual glossary_id esses filtros usam
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
$ids = [51448, 51434, 40789, 83225, 79472];
foreach ($ids as $id) {
    $glossary_id = get_post_meta($id, "_glossary_id", true);
    $label = get_post_meta($id, "_filter_label", true);
    echo $id . " | label: " . $label . " | glossary_id: " . print_r($glossary_id, true) . "\n";
}
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
# Verificar se os glossaries 67, 68, 69 existem no subsite cultura
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
global $wpdb;
$glossaries = $wpdb->get_results("SELECT * FROM wp_2_jet_sm_glossaries LIMIT 20");
foreach ($glossaries as $g) {
    echo "ID: " . $g->id . " | Name: " . $g->name . " | Items: " . count(json_decode($g->glossary, true)) . "\n";
}
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
# Verificar tabelas jet_sm no banco do subsite cultura
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
global $wpdb;
$tables = $wpdb->get_col("SHOW TABLES LIKE \"%jet_sm%\"");
print_r($tables);
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
# Verificar se o filtro 51448 existe como post no subsite cultura
docker exec -u www-data "$CONTAINER" wp --url="https://cambrasmax.local:8484/cultura/" eval '
global $wpdb;
// Verificar em wp_posts do site raiz
$r = $wpdb->get_row("SELECT ID, post_title, post_type FROM wp_posts WHERE ID = 51448");
if ($r) echo "wp_posts: " . print_r($r, true);

$r2 = $wpdb->get_row("SELECT ID, post_title, post_type FROM wp_2_posts WHERE ID = 51448");
if ($r2) echo "wp_2_posts: " . print_r($r2, true);
else echo "Não encontrado em wp_2_posts\n";
' 2>/dev/null

CONTAINER="concertacao-dev-wordpress"
# Listar TODOS os smart filters do site raiz
docker exec -u www-data "$CONTAINER" wp eval '
$filters = get_posts([
    "post_type" => "jet-smart-filters",
    "post_status" => "publish",
    "numberposts" => -1,
    "orderby" => "ID",
    "order" => "ASC",
]);
foreach ($filters as $f) {
    $type = get_post_meta($f->ID, "_filter_type", true);
    $label = get_post_meta($f->ID, "_filter_label", true);
    $source = get_post_meta($f->ID, "_data_source", true);
    $tax = get_post_meta($f->ID, "_source_taxonomy", true);
    echo $f->ID . " | " . $f->post_title . " | type:" . $type . " | label:" . $label . " | source:" . $source . " | tax:" . $tax . "\n";
}
' 2>/dev/null | grep -v "^\[" | grep -v "^$"

CONTAINER="concertacao-dev-wordpress"
# Exportar configuração completa de cada filtro relevante do site raiz
for filter_id in 40843 51448 51434 40789 83225 79472; do
  echo "=== FILTRO $filter_id ==="
  docker exec -u www-data "$CONTAINER" wp eval "
\$meta = get_post_meta($filter_id);
\$post = get_post($filter_id);
echo 'Titulo: ' . \$post->post_title . PHP_EOL;
foreach (\$meta as \$key => \$values) {
    if (substr(\$key, 0, 1) === '_' && \$key !== '_filter_type' && \$key !== '_filter_label' && \$key !== '_data_source' && \$key !== '_source_taxonomy' && \$key !== '_source_post_type' && \$key !== '_glossary_id' && \$key !== '_source_custom_field' && \$key !== '_source_manual_input' && \$key !== '_placeholder' && \$key !== '_is_hierarchical' && \$key !== '_show_empty_terms' && \$key !== '_add_all_option' && \$key !== '_query_var' && \$key !== '_query_builder_query') {
        continue;
    }
    \$val = \$values[0];
    if (!empty(\$val)) {
        echo \$key . ': ' . \$val . PHP_EOL;
    }
}
" 2>/dev/null | grep -v "^\[" | grep -v "^$"
  echo ""
done

CONTAINER="concertacao-dev-wordpress"
# Verificar os glossaries 67, 68, 69 no site raiz
docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
$glossaries = $wpdb->get_results("SELECT id, name, glossary FROM wp_jet_sm_glossaries WHERE id IN (67, 68, 69)");
foreach ($glossaries as $g) {
    $items = json_decode($g->glossary, true);
    echo "ID: " . $g->id . " | Name: " . $g->name . " | Items count: " . count($items) . "\n";
    // Mostrar primeiros 3 itens
    $i = 0;
    foreach ($items as $item) {
        if ($i >= 3) { echo "  ...\n"; break; }
        echo "  - " . print_r($item, true);
        $i++;
    }
}
' 2>/dev/null | grep -v "^\[" | grep -v "^$"

CONTAINER="concertacao-dev-wordpress"
# Verificar tabelas jet_sm no site raiz
docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
$tables = $wpdb->get_col("SHOW TABLES LIKE \"%jet_sm%\"");
print_r($tables);

// Ver glossaries
$glossaries = $wpdb->get_results("SELECT id, name FROM wp_jet_sm_glossaries LIMIT 20");
foreach ($glossaries as $g) {
    echo "Glossary " . $g->id . ": " . $g->name . "\n";
}
' 2>/dev/null | grep -v "^\["

CONTAINER="concertacao-dev-wordpress"
# Verificar no wp_postmeta do site raiz como os filtros 51448 etc. guardam glossary
# O _glossary_id pode ser uma opção de um plugin diferente - verificar qual campo real existe
docker exec -u www-data "$CONTAINER" wp eval '
$meta = get_post_meta(51448);
echo "Todas as meta keys de 51448:\n";
foreach ($meta as $key => $values) {
    $val = is_array($values) ? $values[0] : $values;
    if (!empty($val) && strlen(serialize($val)) < 200) {
        echo "  $key: " . $val . "\n";
    }
}
' 2>/dev/null | grep -v "^\[" | head -50

CONTAINER="concertacao-dev-wordpress"
# Verificar se o glossary_id 67 existe no banco e o que contém
docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
// Tentar localizar onde estão armazenados os glossaries no site raiz
// Pode ser wp_options ou wp_postmeta ou uma tabela custom
$tables = $wpdb->get_col("SHOW TABLES");
foreach ($tables as $t) {
    if (stripos($t, "glossar") !== false || stripos($t, "gloss") !== false) {
        echo "Found table: $t\n";
    }
}

// Verificar em wp_options
$opt = $wpdb->get_results("SELECT option_name FROM wp_options WHERE option_name LIKE \"%glossar%\" LIMIT 5");
foreach ($opt as $o) echo "Option: " . $o->option_name . "\n";
' 2>/dev/null | grep -v "^\["

CONTAINER="concertacao-dev-wordpress"
# Verificar onde os glossaries do JetSmartFilters ficam armazenados
docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
// Checar wp_posts com post_type jet-sm-glossary ou similar
$types = $wpdb->get_col("SELECT DISTINCT post_type FROM wp_posts WHERE post_type LIKE \"%gloss%\"");
print_r($types);

// Talvez seja option do jet smart filters
$opts = $wpdb->get_results("SELECT option_name, LENGTH(option_value) as len FROM wp_options WHERE option_name LIKE \"%jet_smart%\" AND option_name LIKE \"%gloss%\"");
foreach ($opts as $o) echo $o->option_name . " (len: " . $o->len . ")\n";

// Tentar também sem gloss
$opts2 = $wpdb->get_results("SELECT option_name FROM wp_options WHERE option_name LIKE \"%jet_smart_filters%\" LIMIT 10");
foreach ($opts2 as $o) echo "opt: " . $o->option_name . "\n";
' 2>/dev/null | grep -v "^\["

CONTAINER="concertacao-dev-wordpress"
# Verificar o conteúdo da opção jet-smart-filters-settings
docker exec -u www-data "$CONTAINER" wp eval '
$settings = get_option("jet-smart-filters-settings");
print_r($settings);
' 2>/dev/null | grep -v "^\[" | head -30

# Buscar por glossaries de outra forma - talvez seja JetEngine glossaries
docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
// JetEngine glossaries ficam em wp_posts com post_type jet-engine-glossary
$types = $wpdb->get_col("SELECT DISTINCT post_type FROM wp_posts WHERE post_type LIKE \"%jet%\"");
print_r($types);
' 2>/dev/null | grep -v "^\["

CONTAINER="concertacao-dev-wordpress"
# JetEngine glossaries ficam no wp_posts com post_type 'jet-engine' ou são custom data
# Mas o _glossary_id = 67 pode ser um ID de glossary no JetEngine
docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
// Ver posts jet-engine com ID 67
$post = get_post(67);
if ($post) {
    echo "Post 67: " . $post->post_title . " (type: " . $post->post_type . ")\n";
    $meta = get_post_meta(67);
    foreach ($meta as $k => $v) {
        if (strlen(serialize($v)) < 500) {
            echo "  $k: " . print_r($v[0], true) . "\n";
        }
    }
}
' 2>/dev/null | grep -v "^\["

CONTAINER="concertacao-dev-wordpress"
# Glossaries 67/68/69 podem ser IDs de glossaries do JetSmartFilters stored differently
# Vamos verificar a estrutura completa de como criar um filtro via REST API do JSF
# ou ver se o JSF tem suas próprias tabelas

docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
// Ver todas as tabelas
$tables = $wpdb->get_col("SHOW TABLES");
foreach ($tables as $t) {
    if (stripos($t, "jet") !== false) {
        echo $t . "\n";
    }
}
' 2>/dev/null | grep -v "^\["

CONTAINER="concertacao-dev-wordpress"
# Os glossaries do JetSmartFilters ficam armazenados em wp_posts como post_type 'jet-sm-glossary'
# ou podem estar como opção. Vamos verificar via API do JSF
docker exec -u www-data "$CONTAINER" wp eval '
// Verificar se JetSmartFilters tem classe de glossaries
if (class_exists("Jet_Smart_Filters_Glossaries_Manager")) {
    echo "Classe encontrada\n";
    $manager = Jet_Smart_Filters_Glossaries_Manager::instance();
    print_r($manager->get_glossaries());
} elseif (function_exists("jet_smart_filters")) {
    $jsf = jet_smart_filters();
    echo "JSF version: " . $jsf->get_version() . "\n";
    // Tentar glossaries
    if (isset($jsf->glossaries)) {
        print_r($jsf->glossaries->get_glossaries());
    }
} else {
    echo "JSF não encontrado\n";
}
' 2>/dev/null | grep -v "^\[" | head -20

CONTAINER="concertacao-dev-wordpress"
# Buscar onde os glossaries 67/68/69 estão armazenados - talvez sejam IDs de taxonomias do JetEngine
docker exec -u www-data "$CONTAINER" wp eval '
// Listar glossaries do JetEngine (não JetSmartFilters)
if (class_exists("Jet_Engine")) {
    $je = jet_engine();
    echo "JE version: " . $je->get_version() . "\n";

    // Verificar glossaries
    if (isset($je->glossaries) || isset($je->data_stores)) {
        echo "Has glossaries\n";
    }
}

// Verificar via wp_posts
global $wpdb;
$post_types = $wpdb->get_col("SELECT DISTINCT post_type FROM wp_posts WHERE post_type LIKE \"%gloss%\"");
print_r($post_types);

// Procurar ID 67 em wp_jet_post_types
$rows = $wpdb->get_results("SELECT * FROM wp_jet_post_types WHERE id IN (67, 68, 69)");
print_r($rows);

// Procurar ID 67 em wp_jet_taxonomies
$rows2 = $wpdb->get_results("SELECT * FROM wp_jet_taxonomies WHERE id IN (67, 68, 69)");
print_r($rows2);
' 2>/dev/null | grep -v "^\[" | head -30

