docker exec -u www-data "$CONTAINER" wp eval '
global $wpdb;
$rows = $wpdb->get_results("SELECT id, status, labels, args FROM wp_jet_taxonomies WHERE id IN (67, 68, 69)");
foreach ($rows as $r) {
    $labels = maybe_unserialize($r->labels);
